args.sparql:
SELECT DISTINCT ?showLabel WHERE { 
  wd:Q1165506 wdt:P710 ?episode . 
  ?episode wdt:P179 wd:Q2081494 . 
  wd:Q2081494 rdfs:label ?showLabel . 
  FILTER(LANG(?showLabel) = "en") 
}

SELECT ?tvShowLabel WHERE {
  wd:Q1165506 wdt:P710 ?appearance .
  ?appearance wdt:P179 ?tvShow .
  ?tvShow rdfs:label ?tvShowLabel .
  FILTER(LANG(?tvShowLabel) = "en")
} LIMIT 10

SELECT DISTINCT ?showLabel WHERE {
  wd:Q1165506 wdt:P1344 ?show .
  ?show wdt:P31 wd:Q7183641 .
  ?show rdfs:label ?showLabel .
  FILTER(LANG(?showLabel) = "en")
}

SELECT ?show ?showLabel WHERE {
  wd:Q1165506 wdt:P4992 ?show .
  ?show rdfs:label ?showLabel .
  FILTER(LANG(?showLabel) = "en")
}

SELECT DISTINCT ?showLabel WHERE {
  {
    wd:Q1165506 wdt:P710 ?episode .
  }
  UNION
  {
    wd:Q200351 wdt:P710 ?episode .  # Tina Turner
  }
  UNION
  {
    wd:Q363277 wdt:P710 ?episode .  # Ike Turner
  }
  ?episode wdt:P179 wd:Q2081494 .  # Part of The Ed Sullivan Show
  wd:Q2081494 rdfs:label ?showLabel .
  FILTER(LANG(?showLabel) = "en")
}

SELECT DISTINCT ?showLabel WHERE {
  ?episode wdt:P725 wd:Q1165506 .  # Ike & Tina Turner as performer
  ?episode wdt:P179 wd:Q2081494 .  # Part of The Ed Sullivan Show
  wd:Q2081494 rdfs:label ?showLabel .
  FILTER(LANG(?showLabel) = "en")
}

SELECT DISTINCT ?tvShow ?label WHERE {
  ?tvShow wdt:P31/wdt:P279* wd:Q5398426 .  # Instance of TV show
  ?tvShow wdt:P1234 wd:Q1165506 .  # Participant includes Ike & Tina Turner
  ?tvShow rdfs:label ?label .
  FILTER(LANG(?label) = "en")
}

SELECT DISTINCT ?tvshowLabel WHERE {
  ?episode wdt:P175 wd:Q1165506 .  # Performer is Ike & Tina Turner
  ?episode wdt:P179 ?tvshow .        # Episode part of TV series
  ?tvshow rdfs:label ?tvshowLabel .
  FILTER(LANG(?tvshowLabel) = "en")
}

SELECT DISTINCT ?song ?songLabel WHERE {
  ?song wdt:P175 wd:Q1165506 .  # Song performed by Ike & Tina Turner
  ?song wdt:P3153 wd:Q679366 .    # Recorded at Muscle Shoals Sound Studio
  ?song rdfs:label ?songLabel .
  FILTER(LANG(?songLabel) = "en")
}

